  inventoryValue: number;
}
```

**For order-service.ts (inline types):**

```typescript
// Returned by getOrders()
export interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}

// Returned by getOrderById()
export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}
```

---

### Step 4 — Specify exact service function signatures

#### `src/services/product-service.ts`

```typescript
import { products } from "../data.js";
import type { Product } from "../types.js";
import type { ServiceResult } from "../types.js";

export interface ProductFilters {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

export interface ProductListResult { /* as above */ }
export interface ProductDetail extends Product { isLowStock: boolean; inventoryValue: number; }

export function getProducts(filters: ProductFilters): ProductListResult

export function getProductById(id: number): ServiceResult<ProductDetail>

export function adjustStock(id: number, adjustment: number): ServiceResult<ProductDetail>
```

Notes on each:
- `getProducts` never fails (an empty result set is valid), so it returns the result directly with no `ServiceResult` wrapper.
- `getProductById` can fail with 404, so it returns `ServiceResult<ProductDetail>`.
- `adjustStock` can fail with 404 (product not found) or 400 (insufficient stock or non-numeric adjustment). Since the route handler already validates that `adjustment` is a number before calling the service, `adjustStock` only needs to handle the 404 and the "newStock < 0" cases. The `adjustment` parameter type is `number` so the type system prevents passing non-numbers.

#### `src/services/order-service.ts`

```typescript
import { orders, products, getNextOrderId } from "../data.js";
import type { CreateOrderInput, Order } from "../types.js";
import type { ServiceResult } from "../types.js";

export interface OrderFilters {
  userId?: number;
  status?: string;
}

export interface OrderListResult { /* as above */ }
export interface EnrichedOrderItem extends OrderItem { productName: string; }
export interface EnrichedOrder extends Omit<Order, "items"> { items: EnrichedOrderItem[]; }

export function getOrders(filters: OrderFilters): OrderListResult

export function getOrderById(id: number): ServiceResult<EnrichedOrder>

export function createOrder(input: CreateOrderInput): ServiceResult<Order>

export function updateOrderStatus(id: number, status: string): ServiceResult<Order>
```

Notes on each:
- `getOrders` — same reasoning as `getProducts`: never errors.
- `getOrderById` — 404 only.
- `createOrder` — multiple 400 branches (missing fields, empty items, product not found, zero quantity, insufficient stock) plus currently no 404 path (all errors are 400). The input validation for `userId`/`items` presence could be done in the route handler before calling the service, or inside the service. Recommended: move the structural validation (`!userId`, `!Array.isArray(items)`, `items.length === 0`) into the service because it is business-rule data validation, not HTTP parsing. The route handler only needs to type-assert `req.body as CreateOrderInput` and pass it through.
- `updateOrderStatus` — 404 (order not found) and 400 (invalid status string, invalid transition). Both come from the service.

---

### Step 5 — Implement `src/services/product-service.ts` (full logic)

**`getProducts(filters)`** — copies the filter/reduce logic from the route handler verbatim, except it receives `ProductFilters` (already parsed to `number`) rather than raw query strings. Filtering strings and NaN-checking are not needed in the service because the route handler's job is to parse the raw strings.

Wait — this is a critical sequencing decision. There are two valid split points:

- **Split A**: Route handler parses strings to numbers, passes typed `ProductFilters`; service only filters.
- **Split B**: Service receives raw query values and parses them itself.

Split A is cleaner (service stays pure and typed), so: the route handler parses `minPrice`/`maxPrice` strings to floats before calling the service, passes `undefined` when the parse fails (NaN). The service receives `number | undefined` and applies the filter directly.

**`getProductById(id)`** — finds product; returns `{ success: false, error: { status: 404, message: "Product not found" } }` if absent; otherwise returns `{ success: true, data: { ...product, isLowStock: product.stock < 10, inventoryValue: Math.round(product.price * product.stock * 100) / 100 } }`.

**`adjustStock(id, adjustment)`** — finds product (404 if absent), computes newStock, returns 400 error if negative, otherwise mutates `product.stock` and returns the enriched product.

---

### Step 6 — Implement `src/services/order-service.ts` (full logic)

**`getOrders(filters)`** — filters by `userId` (already a number) and `status` (string); computes `totalRevenue`.

**`getOrderById(id)`** — finds order (404 if absent), maps items to enriched items using `products.find`.

**`createOrder(input)`** — the validation sequence is preserved exactly as in the current handler, returning appropriate 400 errors. The loop that builds `orderItems` and deducts stock is moved verbatim into the service. Returns `{ success: true, data: order }` on success.

**`updateOrderStatus(id, status)`** — finds order (404), validates status against `validStatuses` (400), checks transition table (400), mutates `order.status`, returns `{ success: true, data: order }`.

---

### Step 7 — Refactor `src/routes/products.ts`

The route handlers shrink to HTTP-layer concerns only:

**`GET /products`**:
```
Parse category, minPrice, maxPrice from req.query
  - category: string | undefined (pass as-is if typeof === "string")
  - minPrice: parse float, pass undefined if NaN
  - maxPrice: parse float, pass undefined if NaN
Call getProducts({ category, minPrice, maxPrice })
res.json(result)   // no ServiceResult wrapper needed
```

**`GET /products/:id`**:
```
Parse id = parseInt(req.params.id, 10)
const result = getProductById(id)
if (!result.success) { res.status(result.error.status).json({ error: result.error.message }); return; }
res.json(result.data)
```

**`PATCH /products/:id/stock`**:
```
Parse id = parseInt(req.params.id, 10)
Validate adjustment: typeof req.body.adjustment !== "number" → 400 (stays in route; it is HTTP body validation)
const result = adjustStock(id, req.body.adjustment)
if (!result.success) { res.status(result.error.status).json({ error: result.error.message }); return; }
res.json(result.data)
```

Note: keeping the `typeof adjustment !== "number"` check in the route handler is correct. This is HTTP input validation (malformed body), not a business rule. Separating it maintains the principle that services receive already-valid typed inputs.

Import changes: remove direct `products` import; add `import { getProducts, getProductById, adjustStock } from "../services/product-service.js"`.

---

### Step 8 — Refactor `src/routes/orders.ts`

**`GET /orders`**:
```
Parse userId: parseInt if string, else undefined (pass undefined if NaN)
Parse status: string | undefined
Call getOrders({ userId, status })
res.json(result)
```

**`GET /orders/:id`**:
```
Parse id
const result = getOrderById(id)
if (!result.success) { res.status(result.error.status).json({ error: result.error.message }); return; }
res.json(result.data)
```

**`POST /orders`**:
```
const input = req.body as CreateOrderInput
if (!input.userId || !input.items || !Array.isArray(input.items)) → 400 (structural HTTP validation stays)
const result = createOrder(input)
if (!result.success) { res.status(result.error.status).json({ error: result.error.message }); return; }
res.status(201).json(result.data)
```

Wait — re-examining the validation split: `input.items.length === 0` is currently in the route handler. This is a business rule ("an order must have items"), so it should move into `createOrder` in the service and return a 400 `ServiceError`. The route handler only keeps the structural check (`!Array.isArray(input.items)`) because a non-array body is not a meaningful input to pass to the service.

**`PATCH /orders/:id/status`**:
```
Parse id
const { status } = req.body as { status: string }
const result = updateOrderStatus(id, status)
if (!result.success) { res.status(result.error.status).json({ error: result.error.message }); return; }
res.json(result.data)
```

Import changes: remove `orders, products, getNextOrderId` imports; add `import { getOrders, getOrderById, createOrder, updateOrderStatus } from "../services/order-service.js"`. Remove the `CreateOrderInput, OrderItem` type imports (they move to the service file).

---

### Step 9 — Verify no changes needed to `src/app.ts`, `src/data.ts`, `src/types.ts` (structure)

- `src/app.ts` — unchanged. It imports routers, not services directly.
- `src/data.ts` — unchanged. Services import from it.
- `src/types.ts` — add only `ServiceError` and `ServiceResult<T>` at the bottom.
- Tests — unchanged. They only hit HTTP endpoints via Supertest; the internal restructuring is invisible to them.

---

### Implementation Order (with rationale)

1. **Add `ServiceError` and `ServiceResult<T>` to `src/types.ts`** — both service files depend on these types. Do this first so TypeScript can resolve the imports when the service files are created.

2. **Create `src/services/product-service.ts`** — simpler of the two services (no cross-entity references), good to validate the pattern before tackling orders.

3. **Refactor `src/routes/products.ts`** — immediately after, while the service API is fresh. Run tests to confirm product routes still pass before touching orders.

4. **Create `src/services/order-service.ts`** — more complex (cross-references products, uses `getNextOrderId`, multiple 400 paths).

5. **Refactor `src/routes/orders.ts`** — wire up the order service. Run full test suite to confirm all tests pass.

---

### Potential Pitfalls and Mitigations

**Module resolution (`.js` extensions)**: Every import between service files, route files, and data/types must use the `.js` extension in the import path, even though the actual file on disk is `.ts`. This is the Node16 module resolution requirement. For example: `import { getProducts } from "../services/product-service.js"`.

**Mutation of shared in-memory data**: The services mutate the `products` and `orders` arrays directly (same as the current route handlers). This is fine for this in-memory store. The Vitest tests share module state across test cases (note the POST /orders test actually reduces Mouse stock by 1, which could affect price-range filter tests if they run in a different order). No change is needed here since the tests already account for this existing behavior.

**`createOrder` validation split**: The empty-items check (`items.length === 0`) moves into the service. The route handler's existing check for `!Array.isArray(input.items)` stays in the route. The error message `"Order must have at least one item"` must be preserved exactly because the test only checks `res.status` (400), not the message body — but preserving it avoids any future test that might check the message.

**`updateOrderStatus` — untyped `status` string**: The service receives `status: string` and validates it internally. The route handler does not need to pre-validate it; this is fine because the service's 400 error will propagate cleanly.

**`ServiceResult` helper**: Consider adding a small pair of factory functions inline in the service files for cleaner call sites:

```typescript
const ok = <T>(data: T): ServiceResult<T> => ({ success: true, data });
const fail = (status: 400 | 404, message: string): ServiceResult<never> =>
  ({ success: false, error: { status, message } });
```

These are not exported — they are purely internal convenience. They make the service implementations more readable without adding any public API surface.

---

### Summary of All Files Changed

| File | Action |
|---|---|
| `src/types.ts` | Add `ServiceError` and `ServiceResult<T>` |
| `src/services/product-service.ts` | Create new — all product business logic |
| `src/services/order-service.ts` | Create new — all order business logic |
| `src/routes/products.ts` | Refactor — HTTP concerns only, delegate to product service |
| `src/routes/orders.ts` | Refactor — HTTP concerns only, delegate to order service |
| `src/app.ts` | No change |
| `src/data.ts` | No change |
| `tests/*.test.ts` | No change |

---

### Critical Files for Implementation
- `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775342054269-8ku3vs/src/types.ts`
- `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775342054269-8ku3vs/src/services/product-service.ts`
