import { orders, products, getNextOrderId } from "../data.js";
import type { Order, OrderItem, CreateOrderInput, ServiceResult } from "../types.js";

export interface OrderFilters {
  userId?: number;
  status?: string;
}

export interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

export function getOrders(filters: OrderFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrderById(id: number): ServiceResult<EnrichedOrder> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return { success: false, error: { status: 404, message: "Order not found" } };
  }

  const enrichedItems: EnrichedOrderItem[] = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    success: true,
    data: {
      ...order,
      items: enrichedItems,
    },
  };
}

export function createOrder(input: CreateOrderInput): ServiceResult<Order> {
  if (input.items.length === 0) {
    return { success: false, error: { status: 400, message: "Order must have at least one item" } };
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      return { success: false, error: { status: 400, message: `Product ${item.productId} not found` } };
    }

    if (item.quantity <= 0) {
      return { success: false, error: { status: 400, message: "Quantity must be positive" } };
    }

    if (product.stock < item.quantity) {
      return { success: false, error: { status: 400, message: `Insufficient stock for ${product.name}` } };
    }

    product.stock -= item.quantity;

    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += product.price * item.quantity;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return { success: true, data: order };
}

export function updateOrderStatus(id: number, status: string): ServiceResult<Order> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return { success: false, error: { status: 404, message: "Order not found" } };
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];

  if (!validStatuses.includes(status)) {
    return {
      success: false,
      error: { status: 400, message: `Invalid status. Must be one of: ${validStatuses.join(", ")}` },
    };
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    return {
      success: false,
      error: { status: 400, message: `Cannot transition from ${order.status} to ${status}` },
    };
  }

  order.status = status as Order["status"];

  return { success: true, data: order };
}

